import React, { useEffect, useState } from "react";
import socket from "../socket";

function Host() {
  const [players, setPlayers] = useState([]);
  const [question, setQuestion] = useState(null);
  const [index, setIndex] = useState(0);

  useEffect(() => {
    socket.on("playersUpdate", (p) => setPlayers(p));
    socket.on("gameStarted", (q) => setQuestion(q));
    socket.on("nextQuestion", (q) => setQuestion(q));

    return () => {
      socket.off("playersUpdate");
      socket.off("gameStarted");
      socket.off("nextQuestion");
    };
  }, []);

  const startGame = () => {
    socket.emit("startGame");
  };

  const next = () => {
    socket.emit("nextQuestion");
    setIndex((prev) => prev + 1);
  };

  return (
    <div style={styles.container}>
      <h1>🎮 Host Dashboard</h1>

      <button onClick={startGame} style={styles.btn}>
        Start Game
      </button>

      {question && (
        <>
          <h2>{question.question}</h2>
          {question.options.map((opt, i) => (
            <p key={i}>{opt}</p>
          ))}
          <button onClick={next} style={styles.btn}>
            Next Question
          </button>
        </>
      )}

      <h3>Players</h3>
      {players.length === 0 ? (
        <p>No players</p>
      ) : (
        players.map((p, i) => <p key={i}>{p.name}</p>)
      )}
    </div>
  );
}

const styles = {
  container: {
    padding: 20,
  },
  btn: {
    padding: 10,
    margin: 10,
    cursor: "pointer",
  },
};

export default Host;
